# --- TOTP Implementation ---

def generate_totp_secret():
    """Generate a random base32 TOTP secret."""
    random_bytes = os.urandom(20)
    return base64.b32encode(random_bytes).decode('utf-8')


def get_totp_token(secret, time_step=30, digits=6, t=None):
    """Generate a TOTP token for the given secret."""
    if t is None:
        t = int(time.time())
    time_counter = t // time_step
    secret_bytes = base64.b32decode(secret)
    msg = struct.pack('>Q', time_counter)
    hmac_digest = hmac.new(secret_bytes, msg, hashlib.sha1).digest()
    offset = hmac_digest[-1] & 0x0F
    code = struct.unpack('>I', hmac_digest[offset:offset + 4])[0]
    code = code & 0x7FFFFFFF
    code = code % (10 ** digits)
    return str(code).zfill(digits)


def verify_totp_token(secret, token, window=1, time_step=30):
    """Verify a TOTP token with a time window."""
    current_time = int(time.time())
    for i in range(-window, window + 1):
        t = current_time + (i * time_step)
        expected = get_totp_token(secret, time_step=time_step, t=t)
        if hmac.compare_digest(expected, token):
            return True
    return False


# --- Helper Functions ---

def hash_password(password, salt=None):
    """Hash a password with a salt."""
    if salt is None:
        salt = os.urandom(16)
    pwd_hash = hashlib.pbkdf2_hmac('sha256', password.encode(), salt, 100000)
    return salt + pwd_hash


def verify_password(stored_hash, password):
    """Verify a password against a stored hash."""
    salt = stored_hash[:16]
    expected_hash = hash_password(password, salt)
    return hmac.compare_digest(stored_hash, expected_hash)


def login_required(f):
    """Decorator requiring password authentication (MFA can be pending)."""
    @functools.wraps(f)
    def decorated(*args, **kwargs):
        if not session.get('authenticated'):
            return jsonify({'error': 'Authentication required', 'redirect': '/login'}), 401
        return f(*args, **kwargs)
    return decorated


def full_auth_required(f):
    """Decorator requiring both password and MFA authentication."""
    @functools.wraps(f)
    def decorated(*args, **kwargs):
        if not session.get('authenticated'):
            return jsonify({'error': 'Authentication required', 'redirect': '/login'}), 401
        if not session.get('mfa_verified'):
            return jsonify({
                'error': 'MFA verification required for this resource',
                'redirect': '/verify-mfa',
                'mfa_status': 'pending'
            }), 403
        return f(*args, **kwargs)
    return decorated


def get_mfa_status():
    """Get current MFA status for the session."""
    username = session.get('username')
    if not username:
        return 'not_authenticated'
    if session.get('mfa_verified'):
        return 'verified'
    if username in MFA_PENDING:
        return 'pending'
    return 'not_started'


