# --- Routes ---

@app.route('/')
def index():
    if session.get('authenticated'):
        return redirect('/dashboard')
    return redirect('/login')


@app.route('/register', methods=['GET', 'POST'])
def register():
    if request.method == 'GET':
        return render_template_string(REGISTER_TEMPLATE, error=None, mfa_secret=None)

    username = request.form.get('username', '').strip()
    password = request.form.get('password', '')
    confirm_password = request.form.get('confirm_password', '')

    if not username or not password:
        return render_template_string(REGISTER_TEMPLATE, error='Username and password are required.', mfa_secret=None)

    if len(username) < 3:
        return render_template_string(REGISTER_TEMPLATE, error='Username must be at least 3 characters.', mfa_secret=None)

    if len(password) < 8:
        return render_template_string(REGISTER_TEMPLATE, error='Password must be at least 8 characters.', mfa_secret=None)

    if password != confirm_password:
        return render_template_string(REGISTER_TEMPLATE, error='Passwords do not match.', mfa_secret=None)

    if username in USERS_DB:
        return render_template_string(REGISTER_TEMPLATE, error='Username already exists.', mfa_secret=None)

    # Create user
    password_hash = hash_password(password)
    mfa_secret = generate_totp_secret()

    USERS_DB[username] = {
        'password_hash': password_hash,
        'created_at': datetime.utcnow().isoformat(),
        'mfa_enabled': True
    }
    MFA_SECRETS[username] = mfa_secret

    # Generate otpauth URI for QR code scanning
    mfa_uri = f'otpauth://totp/FlaskApp:{username}?secret={mfa_secret}&issuer=FlaskApp'

    return render_template_string(REGISTER_TEMPLATE, error=None, mfa_secret=mfa_secret, mfa_uri=mfa_uri)


@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'GET':
        if session.get('authenticated'):
            return redirect('/dashboard')
        return render_template_string(LOGIN_TEMPLATE, error=None, success=request.args.get('success'))

    username = request.form.get('username', '').strip()
    password = request.form.get('password', '')

    # Validate credentials
    if not username or not password:
        return render_template_string(LOGIN_TEMPLATE, error='Username and password are required.', success=None)

    user = USERS_DB.get(username)
    if not user or not verify_password(user['password_hash'], password):
        # Add a small delay to prevent timing attacks
        time.sleep(0.1)
        return render_template_string(LOGIN_TEMPLATE, error='Invalid username or password.', success=None)

    # Password verified - create session with limited access
    session.clear()
    session['authenticated'] = True
    session['username'] = username
    session['mfa_verified'] = False
    session['login_time'] = datetime.utcnow().isoformat()
    session['session_id'] = secrets.token_hex(16)
    session.permanent = True

    # Mark MFA as pending
    MFA_PENDING[username] = {
        'initiated_at': datetime.utcnow().isoformat(),
        'attempts': 0,
        'max_attempts': 5
    }

    # Generate a background MFA token that can be used for async verification
    bg_token = secrets.token_hex(32)
    BACKGROUND_MFA_TOKENS[bg_token] = {
        'username': username,
        'session_id': session['session_id'],
        'created_at': datetime.utcnow().isoformat(),
        'expires_at': (datetime.utcnow() + timedelta(minutes=10)).isoformat()
    }
    session['bg_mfa_token'] = bg_token

    # Redirect to MFA verification, but user can skip to dashboard with limited access
    return redirect('/verify-mfa')


@app.route('/verify-mfa', methods=['GET', 'POST'])
@login_required
def verify_mfa():
    username = session.get('username')

    if session.get('mfa_verified'):
        return redirect('/dashboard')

    if request.method == 'GET':
        return render_template_string(MFA_TEMPLATE, username=username, error=None, can_skip=True)

    mfa_code = request.form.get('mfa_code', '').strip()

    if not mfa_code:
        return render_template_string(MFA_TEMPLATE, username=username, error='Please enter your MFA code.', can_skip=True)

    # Check attempt limits
    pending = MFA_PENDING.get(username, {})
    if pending.get('attempts', 0) >= pending.get('max_attempts', 5):
        session.clear()
        return redirect('/login')

    # Increment attempts
    if username in MFA_PENDING:
        MFA_PENDING[username]['attempts'] = MFA_PENDING[username].get('attempts', 0) + 1

    # Verify the TOTP token
    mfa_secret = MFA_SECRETS.get(username)
    if not mfa_secret:
        return render_template_string(MFA_TEMPLATE, username=username, error='MFA not configured. Contact admin.', can_skip=True)

    if verify_totp_token(mfa_secret, mfa_code):
        # MFA verified successfully
        session['mfa_verified'] = True
        session['mfa_verified_at'] = datetime.utcnow().isoformat()

        # Clean up pending MFA
        MFA_PENDING.pop(username, None)

        # Clean up background token
        bg_token = session.get('bg_mfa_token')
        if bg_token:
            BACKGROUND_MFA_TOKENS.pop(bg_token, None)

        return redirect('/dashboard')
    else:
        remaining = pending.get('max_attempts', 5) - MFA_PENDING.get(username, {}).get('attempts', 0)
        return render_template_string(
            MFA_TEMPLATE,
            username=username,
            error=f'Invalid MFA code. {remaining} attempts remaining.',
            can_skip=True
        )


@app.route('/api/verify-mfa-background', methods=['POST'])
def verify_mfa_background():
    """Background/async MFA verification endpoint.
    Allows MFA verification to happen asynchronously while user accesses basic resources.
    """
    data = request.get_json()
    if not data:
        return jsonify({'error': 'JSON body required'}), 400

    bg_token = data.get('bg_mfa_token')
    mfa_code = data.get('mfa_code')

    if not bg_token or not mfa_code:
        return jsonify({'error': 'bg_mfa_token and mfa_code are required'}), 400

    token_data = BACKGROUND_MFA_TOKENS.get(bg_token)
    if not token_data:
        return jsonify({'error': 'Invalid or expired background MFA token'}), 401

    # Check expiration
    expires_at = datetime.fromisoformat(token_data['expires_at'])
    if datetime.utcnow() > expires_at:
        BACKGROUND_MFA_TOKENS.pop(bg_token, None)
        return jsonify({'error': 'Background MFA token expired'}), 401

    username = token_data['username']
    mfa_secret = MFA_SECRETS.get(username)

    if not mfa_secret:
        return jsonify({'error': 'MFA not configured'}), 500

    # Check attempt limits
    pending = MFA_PENDING.get(username, {})
    if pending.get('attempts', 0) >= pending.get('max_attempts', 5):
        BACKGROUND_MFA_TOKENS.pop(bg_token, None)
        return jsonify({'error': 'Too many attempts. Please login again.'}), 429

    if username in MFA_PENDING:
        MFA_PENDING[username]['attempts'] = MFA_PENDING[username].get('attempts', 0) + 1

    if verify_totp_token(mfa_secret, mfa_code):
        # Store the verification result so the session can pick it up
        SESSION_STORE[token_data['session_id']] = {
            'mfa_verified': True,
            'mfa_verified_at': datetime.utcnow().isoformat()
        }
        MFA_PENDING.pop(username, None)
        BACKGROUND_MFA_TOKENS.pop(bg_token, None)

        # Also update the Flask session if this request has the right session
        if session.get('session_id') == token_data['session_id']:
            session['mfa_verified'] = True
            session['mfa_verified_at'] = datetime.utcnow().isoformat()

        return jsonify({
            'status': 'success',
            'message': 'MFA verified successfully',
            'mfa_verified': True
        })
    else:
        remaining = pending.get('max_attempts', 5) - MFA_PENDING.get(username, {}).get('attempts', 0)
        return jsonify({
            'status': 'failed',
            'message': f'Invalid MFA code. {remaining} attempts remaining.',
            'mfa_verified': False
        }), 401


@app.before_request
def check_background_mfa_verification():
    """Middleware to check if background MFA verification has completed."""
    if session.get('authenticated') and not session.get('mfa_verified'):
        session_id = session.get('session_id')
        if session_id and session_id in SESSION_STORE:
            stored = SESSION_STORE[session_id]
            if stored.get('mfa_verified'):
                session['mfa_verified'] = True
                session['mfa_verified_at'] = stored.get('mfa_verified_at')
                SESSION_STORE.pop(session_id, None)


