@app.route('/logout')
def logout():
    username = session.get('username')
    session_id = session.get('session_id')
    bg_token = session.get('bg_mfa_token')

    # Clean up
    if username:
        MFA_PENDING.pop(username, None)
    if session_id:
        SESSION_STORE.pop(session_id, None)
    if bg_token:
        BACKGROUND_MFA_TOKENS.pop(bg_token, None)

    session.clear()
    return redirect('/login?success=Logged out successfully')


# --- Utility endpoint for development/testing ---

@app.route('/dev/generate-code/<username>')
def dev_generate_code(username):
    """Development-only endpoint to generate a current TOTP code for testing."""
    if not app.debug:
        return jsonify({'error': 'Only available in debug mode'}), 403

    mfa_secret = MFA_SECRETS.get(username)
    if not mfa_secret:
        return jsonify({'error': 'User not found or MFA not configured'}), 404

    code = get_totp_token(mfa_secret)
    return jsonify({
        'username': username,
        'current_code': code,
        'valid_for': f'{30 - (int(time.time()) % 30)} seconds',
        'note': 'This endpoint is only available in debug mode'
    })


@app.route('/dev/users')
def dev_users():
    """Development-only endpoint to list registered users."""
    if not app.debug:
        return jsonify({'error': 'Only available in debug mode'}), 403

    users = {}
    for username, data in USERS_DB.items():
        users[username] = {
            'created_at': data.get('created_at'),
            'mfa_enabled': data.get('mfa_enabled'),
            'mfa_secret': MFA_SECRETS.get(username, 'N/A')
        }
    return jsonify({'users': users})


# --- Error Handlers ---

@app.errorhandler(404)
def not_found(e):
    return jsonify({'error': 'Not found'}), 404


@app.errorhandler(500)
def server_error(e):
    return jsonify({'error': 'Internal server error'}), 500


